1	<!DOCTYPE html>
2	<html lang="zh-CN">
3	<head>
4	<meta charset="utf-8">
5	<title>OKKI 客户管道看板 — 2026-05-12</title>
6	<style>
7	  :root {
8	    --bg-primary: #f5f5f7;
9	    --bg-secondary: #ffffff;
10	    --bg-tertiary: #e5e5e7;
11	    --border: #d1d1d6;
12	    --text-primary: #1d1d1f;
13	    --text-secondary: #86868b;
14	    --text-tertiary: #aeaeb2;
15	    --accent: #0071e3;
16	    --success: #34c759;
17	    --warning: #ff9f0a;
18	    --error: #ff3b30;
19	  }
20	  @media (prefers-color-scheme: dark) {
21	    :root {
22	      --bg-primary: #1d1d1f;
23	      --bg-secondary: #2d2d2f;
24	      --bg-tertiary: #3d3d3f;
25	      --border: #424245;
26	      --text-primary: #f5f5f7;
27	      --text-secondary: #86868b;
28	      --text-tertiary: #636366;
29	      --accent: #0a84ff;
30	    }
31	  }
32	  * { box-sizing: border-box; margin: 0; padding: 0; }
33	  body {
34	    font-family: system-ui, -apple-system, BlinkMacSystemFont, sans-serif;
35	    background: var(--bg-primary);
36	    color: var(--text-primary);
37	    line-height: 1.5;
38	    padding: 20px 24px;
39	    max-width: 1400px;
40	    margin: 0 auto;
41	  }
42	  h1 { font-size: 1.3rem; margin-bottom: 4px; }
43	  .subtitle { color: var(--text-secondary); font-size: 0.85rem; margin-bottom: 20px; }
44	
45	  .kpi-grid { display: grid; grid-template-columns: repeat(6, 1fr); gap: 10px; margin-bottom: 20px; }
46	  .kpi { color: #fff; padding: 14px 12px; border-radius: 8px; text-align: center; }
47	  .kpi .num { font-size: 28px; font-weight: 700; }
48	  .kpi .lbl { font-size: 11px; opacity: 0.9; }
49	
50	  .card { background: var(--bg-secondary); border: 1px solid var(--border); border-radius: 10px; overflow: hidden; margin-bottom: 16px; }
51	  .card-hd { background: var(--bg-tertiary); padding: 10px 14px; font-weight: 600; font-size: 13px; border-bottom: 1px solid var(--border); }
52	  .card-hd span { font-weight: normal; font-size: 11px; color: var(--text-secondary); }
53	
54	  table.mx { width: 100%; border-collapse: collapse; font-size: 12px; }
55	  table.mx th { padding: 6px 8px; border: 1px solid var(--border); background: var(--bg-tertiary); font-weight: 600; }
56	  table.mx td { border: 1px solid var(--border); }
57	  table.mx td.rl { text-align: left; font-weight: 600; padding: 6px 8px; }
58	
59	  .flex { display: flex; gap: 16px; margin-bottom: 16px; }
60	  .flex-1 { flex: 1; }
61	  .flex-320 { flex: 0 0 340px; }
62	
63	  .silence-row { display: flex; justify-content: space-between; align-items: center; padding: 10px 14px; border-bottom: 1px solid var(--border); cursor: pointer; }
64	  .silence-detail { display: none; padding: 8px 14px; border-bottom: 1px solid var(--border); }
65	
66	  table.sub { width: 100%; border-collapse: collapse; font-size: 12px; }
67	  table.sub th { padding: 8px; border: 1px solid var(--border); text-align: left; background: var(--bg-tertiary); font-weight: 600; }
68	  table.sub td { padding: 8px; border: 1px solid var(--border); }
69	  table.sub td.nc { text-align: center; }
70	
71	  .trend-row { display: flex; justify-content: space-between; align-items: center; padding: 6px 0; border-bottom: 1px solid var(--border); }
72	  .trend-row .det { font-size: 11px; color: var(--text-secondary); }
73	
74	  .footer { margin-top: 24px; padding: 14px; border-top: 1px solid var(--border); font-size: 11px; color: var(--text-secondary); text-align: center; }
75	  .footer a { color: var(--accent); }
76	
77	  .modal-overlay { display:none; position:fixed; top:0; left:0; right:0; bottom:0; background:rgba(0,0,0,0.45); z-index:9999; justify-content:center; align-items:center; }
78	  .modal-overlay.show { display:flex; }
79	  .modal-box { background:var(--bg-secondary); border-radius:10px; width:700px; max-width:92vw; max-height:75vh; overflow-y:auto; box-shadow:0 8px 30px rgba(0,0,0,0.25); }
80	  @media (prefers-color-scheme: dark) { .modal-box { box-shadow:0 8px 30px rgba(0,0,0,0.6); } }
81	  .modal-hd { display:flex; justify-content:space-between; align-items:center; padding:14px 18px; border-bottom:1px solid var(--border); font-weight:600; font-size:15px; position:sticky; top:0; background:var(--bg-secondary); border-radius:10px 10px 0 0; z-index:1; }
82	  .modal-close { cursor:pointer; font-size:20px; color:var(--text-secondary); line-height:1; padding:0 4px; border:none; background:none; }
83	  .modal-close:hover { color:var(--text-primary); }
84	  .modal-body { padding:14px 18px; }
85	  .modal-body table { width:100%; border-collapse:collapse; font-size:12px; }
86	  .modal-body th { padding:6px 8px; border:1px solid var(--border); background:var(--bg-tertiary); text-align:left; font-weight:600; }
87	  .modal-body td { padding:6px 8px; border:1px solid var(--border); }
88	</style>
89	</head>
90	<body>
91	
92	<h1>OKKI 客户管道看板</h1>
93	<div class="subtitle">生成时间：2026-05-12 | 数据源：s1_enhanced_full.json + tm_conversations_latest.json | 全覆盖 463 客户</div>
94	
95	<!-- KPI -->
96	<div class="kpi-grid">
97	  <div class="kpi" style="background:#1a5276;"><div class="num">463</div><div class="lbl">总客户</div></div>
98	  <div class="kpi" style="background:#1a5276;"><div class="num">17</div><div class="lbl">3天活跃</div></div>
99	  <div class="kpi" style="background:#c0392b;"><div class="num">139</div><div class="lbl">超90天无互动</div></div>
100	  <div class="kpi" style="background:#e67e22;"><div class="num">0</div><div class="lbl">未读消息</div></div>
101	  <div class="kpi" style="background:#27ae60;"><div class="num">0</div><div class="lbl">本期变动</div></div>
102	  <div class="kpi" style="background:#8e44ad;"><div class="num">220</div><div class="lbl">需行动</div></div>
103	</div>
104	
105	<!-- 双轴矩阵 -->
106	<div class="card">
107	  <div class="card-hd">客户双轴矩阵 <span>（生命周期 × 质量）— 点击格子展开客户名单 + 标准动作</span></div>
108	  <div style="overflow-x:auto;">
109	    <table class="mx">
110	      <tr>
111	        <th style="text-align:left;min-width:80px;">阶段 \ 等级</th>
112	        <th>S</th><th>A</th><th>B</th><th>C</th><th>D</th>
113	      </tr>
114	      <tr>
115	        <td class="rl">待回复</td>
116	        <td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td><td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td><td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td><td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td><td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td>
117	      </tr><tr>
118	        <td class="rl">初询沟通</td>
119	        <td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td><td style="text-align:center;padding:6px 8px;border:1px solid var(--border);color:var(--text-tertiary);">0</td><td style="text-align:center;padding:6px 8px;border:1px solid var(--border);cursor:pointer;background:rgba(255,159,10,0.5);font-weight:600;"
120	    onclick="openModal('初询沟通','B')">122</td><td style="text-align:center;padding:6px 8px;border:1px solid var(--border);cursor:pointer;background:rgba(255,159,10,0.5);font-weight:600;"

1	const fs = require('fs');
2	const path = require('path');
3	
4	const s1 = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'data', 's1_classification.json'), 'utf8'));
5	const chatDir = path.join(__dirname, '..', 'data', 'chat_history');
6	const NOW = Date.now();
7	const DAY = 86400000;
8	const OUR_UID = '2500000853693@icbu';
9	
10	// ── 工具函数 ──
11	const SYS_PATTERNS = [
12	  '自动接待将不再触发', 'Since you have read the conversation',
13	  'Marco大模型翻译', '阿里国际Marco大模型翻译',
14	  '买家有流失风险', 'Buyer has churn risk',
15	  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
16	  '反馈', 'AI给您生成了一条回复建议',
17	  'You have a visitor', 'This buyer has been pre-screened',
18	  '当前买家首次给您发消息', 'AI给您生成',
19	];
20	function isSys(c) { const t = c && c.text && c.text.content || ''; if (!t.trim()) return true; for (const p of SYS_PATTERNS) if (t.includes(p)) return true; return false; }
21	function getText(c) { return c && c.text && c.text.content || ''; }
22	
23	const Q_PATTERNS = [/\?/, /(what|how|when|where|which|who|why|whom)/i, /(can you|could you|would you|will you|do you|is it|are you)/i, /(please.*(send|give|tell|quote|share|confirm|advise|provide|let me know))/i, /(i need|i want|i would like|i'm looking for|we need|we want|we are looking)/i, /[吗呢吧啊]/, /[？]/, /(价格|报价|多少钱|什么价)/, /(样品|sample|打样)/i, /(MOQ|起订量|最小.*量)/i, /(交期|delivery.*time|lead.*time)/i];
24	function isQuestion(text) { if (!text || text.length < 3) return false; for (const p of Q_PATTERNS) if (p.test(text)) return true; return false; }
25	
26	function assessQuality(qText, rText) {
27	  if (!rText || rText.trim().length === 0) return { q: '未回复', s: 0 };
28	  const len = rText.trim().length;
29	  if (/^(ok|okay|yes|no|thanks|thank you|got it|noted|well|sure|好的|收到|嗯|哦|知道了)[\s,.]*$/i.test(rText.trim()) || len < 15) return { q: '敷衍回复', s: 1 };
30	  if (len < 50) return { q: '简短回复', s: 2 };
31	  const qw = (qText || '').toLowerCase().replace(/[?？,.]/g, '').split(/\s+/).filter(w => w.length > 3);
32	  const rl = rText.toLowerCase();
33	  const m = qw.filter(w => rl.includes(w));
34	  return (m.length / Math.max(qw.length, 1) >= 0.3 || len >= 100) ? { q: '充分回复', s: 3 } : { q: '简短回复', s: 2 };
35	}
36	
37	// ── 生命周期判定 ──
38	function determineLifecycle(e) {
39	  const { hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasQuantity, realMsgs, customerMsgs, ourMsgs, daysAgo, lastCustomerMsgDays, questionUnanswered, lastCustQuestion } = e;
40	  const fullText = ((e.latestOurMsg || '') + ' ' + (e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '')).toLowerCase();
41	
42	  // 售后：质量问题/投诉
43	  if (/(problem|issue|damage|broken|wrong|defect|complain|refund|return|bad quality|poor quality|not good|有问题|坏的|退货|退款|投诉)/i.test(fullText)) return { stage: 8, label: '售后', icon: '🔧' };
44	
45	  // 订单执行中：付款确认+生产/发货讨论
46	  if (hasPI && /(paid|payment.*done|deposit.*paid|生产|produc|ship.*out|on the way|tracking|dispatch)/i.test(fullText)) return { stage: 6, label: '订单执行中', icon: '📦' };
47	
48	  // 已签收
49	  if (hasPI && /(received|arrived|delivered|got.*goods|收到.*货|签收)/i.test(fullText)) return { stage: 7, label: '已签收', icon: '✅' };
50	
51	  // PI已发
52	  if (hasPI && daysAgo <= 14) return { stage: 5, label: 'PI已发', icon: '📄' };
53	
54	  // 谈判/样品
55	  if ((hasPrice || hasSample) && hasQuantity && realMsgs >= 10 && daysAgo <= 7) return { stage: 4, label: '谈判/样品', icon: '🤝' };
56	  if (hasSample && daysAgo <= 14 && realMsgs >= 5) return { stage: 4, label: '谈判/样品', icon: '🤝' };
57	
58	  // 报价已发
59	  if (hasPrice && daysAgo <= 14) return { stage: 3, label: '报价已发', icon: '💰' };
60	
61	  // 待回复：客户有新消息未回
62	  if (questionUnanswered || (customerMsgs > ourMsgs && lastCustomerMsgDays <= 1)) return { stage: 1, label: '待回复', icon: '🔴' };
63	
64	  // 初询沟通
65	  if (realMsgs >= 1 && daysAgo <= 14) return { stage: 2, label: '初询沟通', icon: '📋' };
66	
67	  return { stage: 0, label: '待分类', icon: '❓' };
68	}
69	
70	// ── 沉默副状态 ──
71	function silenceLabel(days) {
72	  if (days >= 90) return '沉淀(90d+)';
73	  if (days >= 30) return '深度沉默(30-90d)';
74	  if (days >= 14) return '长期沉默(14-30d)';
75	  if (days >= 7) return '中期沉默(7-14d)';
76	  if (days >= 3) return '短期沉默(3-7d)';
77	  return '';
78	}
79	
80	// ── 质量等级判定 ──
81	function determineQuality(e) {
82	  const fullText = ((e.latestOurMsg || '') + ' ' + (e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '') + ' ' + (e.latestOurMsg || '')).toLowerCase();
83	
84	  // S 级信号
85	  const sSignals = [];
86	  if (/(brand|odm|oem|logo|label|custom.*packag|hangtag|barcode|private.*label|own.*design)/i.test(fullText)) sSignals.push('品牌/ODM/定制包装');
87	  if (/(amazon|walmart|shopify|retail.*chain|distributor.*network|wholesale.*channel)/i.test(fullText)) sSignals.push('分销渠道');
88	  if (/(\d{4,}\s*(pcs|pieces|units|件)|\b[5-9]\d{2,3}\s*(pcs|pieces|units))/i.test(fullText)) sSignals.push('大批量');
89	  if (/(website|store|shop|company.*name|business.*card)/i.test(fullText)) sSignals.push('公司资料');
90	
91	  // C/D 信号
92	  const cSignals = [];
93	  if (/(for myself|for my kid|for my baby|personal use|自用|送人|gift)/i.test(fullText)) cSignals.push('个人自用');
94	  if (/(\b[1-2]?\d\s*(pcs|pieces|units|件)\b|just.*few|small.*quantity|少量)/i.test(fullText)) cSignals.push('极小量');
95	
96	  // D 信号
97	  if (e.realMsgs <= 2 && e.customerMsgs === 0) return { grade: 'D', label: '无关/废弃', reason: '仅系统消息/无真实对话', auto: true };
98	  if (/(adult|成人|men.*wear|not.*baby|not.*kid)/i.test(fullText) && !(/baby|kid|child|infant/i.test(fullText))) return { grade: 'D', label: '无关', reason: '品类不匹配', auto: true };
99	
100	  if (sSignals.length >= 2) return { grade: 'S', label: '战略客户', reason: sSignals.join('+'), auto: true };
101	  if (sSignals.length >= 1) return { grade: 'A', label: '优质客户', reason: sSignals.join('+') + '(信号待验证)', auto: true };
102	  if (cSignals.length >= 2) return { grade: 'C', label: '低价值', reason: cSignals.join('+'), auto: true };
103	
104	  // 有实质对话但信息不足 → B
105	  if (e.realMsgs >= 5 && e.customerMsgs >= 2) return { grade: 'B', label: '普通客户', reason: '信息不足自动定B', auto: true };
106	  if (e.hasPrice || e.hasSample || e.hasQuantity) return { grade: 'B', label: '普通客户', reason: '有实质讨论但规模未知', auto: true };
107	
108	  return { grade: 'B', label: '普通客户', reason: '信息不足默认B', auto: true };
109	}
110	
111	// ── 主循环 ──
112	const candidates = [...(s1.results[1] || []), ...(s1.results[2] || [])];
113	console.log('处理 ' + candidates.length + ' 个 P1+P2 候选...\n');
114	
115	const enhanced = [];
116	for (const c of candidates) {
117	  const fid = c.cid ? c.cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : '';
118	  const fp = path.join(chatDir, fid);
119	
120	  let msgCount = 0, customerMsgs = 0, ourMsgs = 0, sysMsgs = 0;
121	  let hasPI = false, hasAddress = false, hasOrderSignal = false, hasPrice = false;
122	  let hasSample = false, hasFreight = false, hasMOQ = false, hasQuantity = false;
123	  let latestOurMsg = '', latestOurDate = '', latestCustMsg = '', latestCustDate = '';
124	  let lastCustomerMsgDays = 9999;
125	  let lastCustQuestion = '', lastCustQuestionDate = '', ourResponseQuality = 'N/A';
126	  let responseGapDays = -1, questionUnanswered = false;
127	
128	  if (fs.existsSync(fp)) {
129	    try {
130	      const data = JSON.parse(fs.readFileSync(fp, 'utf8'));
131	      const msgs = data.messages || [];
132	      msgCount = msgs.length;
133	
134	      for (const m of msgs) {
135	        const msg = m.message || m;
136	        const uid = msg.sender && msg.sender.uid || '';
137	        const text = getText(msg.content);
138	        const date = msg.createAt || '';
139	        if (isSys(msg.content)) { sysMsgs++; continue; }
140	
141	        if (uid === OUR_UID) {
142	          ourMsgs++; if (date > latestOurDate) { latestOurDate = date; latestOurMsg = text; }
143	        } else if (uid) {
144	          customerMsgs++;
145	          if (date > latestCustDate) { latestCustDate = date; latestCustMsg = text; }
146	          if (date) lastCustomerMsgDays = Math.min(lastCustomerMsgDays, Math.floor((NOW - new Date(date).getTime()) / DAY));
147	        }
148	
149	        const lc = text.toLowerCase();
150	        if (/pi|proforma\s*invoice|invoice\s*sent|付款|deposit|定金|tt\s|wire\s*transfer|bank\s*transfer/.test(lc + text)) hasPI = true;
151	        if (/(address|地址|city|country|delivery\s*address|where.*ship|send.*to|destination)/.test(lc)) hasAddress = true;
152	        if (/(place.*order|make.*order|confirm.*order|下单|order.*confirmed|want.*to.*order|proceed.*order|ready.*order)/.test(lc)) hasOrderSignal = true;
153	        if (/(price|quotation|quote|报价|unit.*price|each.*cost)/.test(lc)) hasPrice = true;
154	        if (/(sample|样品)/.test(lc)) hasSample = true;
155	        if (/(freight|shipping|运费|物流|delivery|transport|courier|dhl|fedex)/.test(lc)) hasFreight = true;
156	        if (/(moq|minimum.*order|最低.*数量|500.*piece|最小.*订单)/.test(lc)) hasMOQ = true;
157	        if (/(quantity|数量|how.*many|pieces|pcs|units)/.test(lc)) hasQuantity = true;
158	      }
159	
160	      // 找最后的客户提问
161	      const sortedMsgs = [...msgs].filter(m => !isSys((m.message || m).content)).sort((a, b) => ((b.message || b).createAt || 0) - ((a.message || a).createAt || 0));
162	      for (const m of sortedMsgs) {
163	        const msg = m.message || m;
164	        const uid = msg.sender && msg.sender.uid || '';
165	        const text = getText(msg.content);
166	        if (uid && uid !== OUR_UID && isQuestion(text)) { lastCustQuestion = text; lastCustQuestionDate = msg.createAt || ''; break; }
167	      }
168	
169	      if (lastCustQuestion && lastCustQuestionDate) {
170	        const qTs = new Date(lastCustQuestionDate).getTime();
171	        let respText = '', respDate = '';
172	        for (const m of [...sortedMsgs].reverse()) {
173	          const msg = m.message || m;
174	          const ts = (msg.createAt || 0);
175	          if ((msg.sender && msg.sender.uid) === OUR_UID && ts > qTs) { respText = getText(msg.content); respDate = msg.createAt || ''; break; }
176	        }
177	        if (respText) {
178	          const gapH = (new Date(respDate).getTime() - qTs) / 3600000;
179	          responseGapDays = Math.round(gapH / 24 * 10) / 10;
180	          const a = assessQuality(lastCustQuestion, respText);
181	          ourResponseQuality = a.q + ' (' + responseGapDays + 'd)';
182	        } else {
183	          ourResponseQuality = '未回复';
184	          responseGapDays = Math.round((NOW - qTs) / DAY * 10) / 10;
185	          questionUnanswered = true;
186	        }
187	      }
188	    } catch (e) { /* skip corrupt */ }
189	  }
190	
191	  const realMsgs = customerMsgs + ourMsgs;
192	  const cRatio = realMsgs > 0 ? Math.round(customerMsgs / realMsgs * 100) : 0;
193	  const country = c.country || '';
194	  const coreMarkets = ['SD', 'EG', 'CD', 'ZM', 'CI', 'SA', 'AE'];
195	  const isCore = coreMarkets.includes(country);
196	
197	  const obj = {
198	    name: c.name, country, isCore, daysAgo: c.daysAgo,
199	    msgCount, customerMsgs, ourMsgs, sysMsgs, realMsgs, cRatio,
200	    lastCustomerMsgDays: lastCustomerMsgDays === 9999 ? '-' : lastCustomerMsgDays,
201	    latestOurMsg: latestOurMsg.substring(0, 100), latestCustMsg: latestCustMsg.substring(0, 100),
202	    hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasFreight, hasMOQ, hasQuantity,
203	    lastCustQuestion: lastCustQuestion.substring(0, 200), ourResponseQuality, responseGapDays, questionUnanswered,
204	    cid: c.cid, filename: fid,
205	  };
206	
207	  // 双轴分类
208	  const lc = determineLifecycle(obj);
209	  const ql = determineQuality(obj);
