function generateDashboard(data, urgents) {
  const now = new Date();
  const today = now.toISOString().slice(0, 10);
  const timeStr = now.toLocaleString('zh-CN');

  const byStage = {}; for (const e of data) { const k = e.stageLabel; if (!byStage[k]) byStage[k] = []; byStage[k].push(e); }

  const signals = data.filter(e => e.actionSignals.length > 0).sort((a, b) => a.actionSignals.length - b.actionSignals.length).reverse();

  const gradeColors = { S: '#8b0000', A: '#c0392b', B: '#2c3e50', C: '#7f8c8d', D: '#bdc3c7' };
  const stageColors = { '待回复': '#e74c3c', 'PI已发': '#e67e22', '谈判/样品': '#f39c12', '报价已发': '#3498db', '初询沟通': '#27ae60', '订单执行中': '#9b59b6', '已签收': '#2ecc71', '售后': '#e74c3c' };

  const cardData = [
    { label: '待回复', num: urgents.length, color: '#e74c3c' },
    { label: 'S/A级客户', num: gCount.S + gCount.A, color: '#c0392b' },
    { label: '提问未回', num: enhanced.filter(e => e.questionUnanswered).length, color: '#e67e22' },
    { label: '待处理信号', num: signals.length, color: '#d35400' },
    { label: '活跃总数', num: data.length, color: '#2c3e50' },
  ];

  const stageRows = ['待回复', 'PI已发', '谈判/样品', '报价已发', '初询沟通'].map(s =>
    (byStage[s] || []).map(e => `
      <tr>
        <td><span class="stage-dot" style="background:${stageColors[s] || '#888'}"></span> ${s}</td>
        <td><b>${e.name}</b></td>
        <td>${e.country || '??'}${e.isCore ? ' ★' : ''}</td>
        <td><span class="grade-badge" style="background:${gradeColors[e.grade] || '#888'}">${e.grade}</span> ${e.gradeLabel}</td>
        <td>${e.daysAgo}d前</td>
        <td>${e.lastCustomerMsgDays === '-' ? '-' : e.lastCustomerMsgDays + 'd'}</td>
        <td class="q-preview" title="${(e.lastCustQuestion || '').replace(/"/g, '&quot;')}">${(e.lastCustQuestion || '-').substring(0, 50)}</td>
        <td>${e.questionUnanswered ? '<span class="tag danger">未回复</span>' : e.ourResponseQuality.startsWith('敷衍') ? '<span class="tag warn">' + e.ourResponseQuality + '</span>' : e.ourResponseQuality.startsWith('简短') ? '<span class="tag info">' + e.ourResponseQuality + '</span>' : '<span class="tag ok">' + e.ourResponseQuality + '</span>'}</td>
        <td>${e.responseGapDays >= 0 ? (e.responseGapDays > 3 ? '<b class="num-danger">' + e.responseGapDays + 'd</b>' : e.responseGapDays + 'd') : '-'}</td>
        <td>${e.silenceState || '-'}</td>
      </tr>`).join('')
  ).join('');

